<!-- ===== EXPERIENCE ===== -->
<section class="experience-section has-deco">
  <div class="deco"
    style="width:200px;top:260px;right:-30px;--db:rotate(-12deg);animation:df 11s ease-in-out 0s infinite;"><img
      src="data:image/png;base64,"
      style="opacity:0.35"></div>
  <div class="deco"
    style="width:170px;bottom:-30px;left:-20px;--db:rotate(10deg);animation:df2 9s ease-in-out 2s infinite;"><img
      src="data:image/png;base64,"
      style="opacity:0.35"></div>

  <div class="section-label"><?= __('exp.label') ?></div>
  <h2 class="section-title" style="color:var(--dark);"><?= __('exp.title') ?><br><span
      style="color:var(--pink);"><?= __('exp.title_highlight') ?></span>
  </h2>

  <div class="experience-grid">
    <div class="exp-card reveal">
      <span class="exp-icon">🥁</span>
      <div class="exp-title"><?= __('exp.live_samba') ?></div>
      <p class="exp-desc"><?= __('exp.live_samba_desc') ?></p>
    </div>
    <div class="exp-card reveal reveal-delay-1">
      <span class="exp-icon">🎧</span>
      <div class="exp-title"><?= __('exp.dj_sets') ?></div>
      <p class="exp-desc"><?= __('exp.dj_sets_desc') ?></p>
    </div>
    <div class="exp-card reveal reveal-delay-2">
      <span class="exp-icon">🍹</span>
      <div class="exp-title"><?= __('exp.drinks') ?></div>
      <p class="exp-desc"><?= __('exp.drinks_desc') ?></p>
    </div>
    <div class="exp-card reveal reveal-delay-3">
      <span class="exp-icon">🍔</span>
      <div class="exp-title"><?= __('exp.food') ?></div>
      <p class="exp-desc"><?= __('exp.food_desc') ?></p>
    </div>
    <div class="exp-card reveal">
      <span class="exp-icon">💄</span>
      <div class="exp-title"><?= __('exp.beauty') ?></div>
      <p class="exp-desc"><?= __('exp.beauty_desc') ?></p>
    </div>
    <div class="exp-card reveal reveal-delay-1">
      <span class="exp-icon">🎨</span>
      <div class="exp-title"><?= __('exp.tattoo') ?></div>
      <p class="exp-desc"><?= __('exp.tattoo_desc') ?></p>
    </div>
    <div class="exp-card reveal reveal-delay-2">
      <span class="exp-icon">⭐</span>
      <div class="exp-title"><?= __('exp.vip') ?></div>
      <p class="exp-desc"><?= __('exp.vip_desc') ?></p>
    </div>
    <div class="exp-card reveal reveal-delay-3">
      <span class="exp-icon">📸</span>
      <div class="exp-title"><?= __('exp.photo') ?></div>
      <p class="exp-desc"><?= __('exp.photo_desc') ?></p>
    </div>
    <div class="exp-card reveal">
      <span class="exp-icon">🎉</span>
      <div class="exp-title"><?= __('exp.community') ?></div>
      <p class="exp-desc"><?= __('exp.community_desc') ?></p>
    </div>
  </div>
</section>